#!/usr/bin/env node
const config=require("./config"),DiscordNotifier=require("./services/discordNotifier");async function testDiscordConnection(){if(console.log("🔗 Testing Discord Connection"),console.log("=".repeat(40)),console.log("📋 Configuration:"),console.log("   Bot token: "+(config.discord.botToken?"Set":"Missing")),console.log("   Channel ID: "+(config.discord.channelId?"Set":"Missing")),console.log("   NFTs Role ID: "+(config.discord.nftsRoleId?"Set":"Missing")),config.discord.botToken&&config.discord.channelId){try{console.log("\n🔗 Attempting to connect to Discord...");const notifier=new DiscordNotifier;await notifier.connect(),console.log("✅ Discord connection successful!"),notifier.isReady?console.log("✅ Bot is ready to send notifications"):console.log("⚠️ Bot is not ready yet");try{const channel=await notifier.client.channels.fetch(config.discord.channelId);channel?console.log(`✅ Channel access successful: #${channel.name}`):console.log("❌ Channel not found")}catch(error){console.log("❌ Channel access failed:",error.message)}try{(new Date).toISOString();await notifier.sendNotification({type:"test",walletName:"Test Wallet",walletAddress:"0x1234567890123456789012345678901234567890",tokenName:"Test NFT",tokenId:"1",contractAddress:"0x1234567890123456789012345678901234567890",transactionHash:"0x1234567890123456789012345678901234567890",chainName:"Ethereum",timestamp:Date.now(),price:.1,priceUSD:200}),console.log("✅ Test notification sent successfully!")}catch(error){console.log("❌ Test notification failed:",error.message)}await notifier.disconnect(),console.log("🔌 Discord connection closed")}catch(error){console.error("❌ Discord connection test failed:",error.message),error.message.includes("token")?console.log("💡 Check your DISCORD_BOT_TOKEN environment variable"):error.message.includes("channel")?console.log("💡 Check your DISCORD_CHANNEL_ID environment variable"):error.message.includes("permissions")&&console.log("💡 Check bot permissions in Discord server")}console.log("\n"+"=".repeat(40))}else console.log("❌ Missing required Discord configuration")}testDiscordConnection().catch(console.error);